#!/usr/bin/env node
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ICON_PATH = join(__dirname, "..", "icon-48.png");
const outFile = join(__dirname, "..", "src", "icon-bundled.ts");

const iconBase64 = readFileSync(ICON_PATH).toString("base64");

const lines = [
  "// AUTO-GENERATED by scripts/bundle-icon.mjs — do not edit by hand.",
  "// Regenerate by running any npm script (prebuild/pretest/pretypecheck hook calls bundle-icon).",
  "",
  `export const ICON_DATA_URI: string = "data:image/png;base64,${iconBase64}";`,
  "",
];

writeFileSync(outFile, lines.join("\n"), "utf8");
console.error(`bundle-icon: wrote 48x48 icon to ${outFile}`);
